/**
 * @suppress
 */
public object FfiConverterTypeNexusClient: FfiConverter<NexusClient, Pointer> {

    override fun lower(value: NexusClient): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): NexusClient {
        return NexusClient(value)
    }

    override fun read(buf: ByteBuffer): NexusClient {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: NexusClient) = 8UL

    override fun write(value: NexusClient, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



