public object FfiConverterTypeAgentCommandFfi: FfiConverterRustBuffer<AgentCommandFfi> {
    override fun read(buf: ByteBuffer): AgentCommandFfi {
        return AgentCommandFfi(
            FfiConverterString.read(buf),
            FfiConverterString.read(buf),
        )
    }

    override fun allocationSize(value: AgentCommandFfi) = (
            FfiConverterString.allocationSize(value.`command`) +
            FfiConverterString.allocationSize(value.`description`)
    )

    override fun write(value: AgentCommandFfi, buf: ByteBuffer) {
            FfiConverterString.write(value.`command`, buf)
            FfiConverterString.write(value.`description`, buf)
    }
}



